Here's the full pattern:

**XAML** — wrap `CollectionView` in a `RefreshView` for pull-to-refresh:

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="Auto,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel** (using CommunityToolkit.Mvvm):

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    [ObservableProperty]
    private ObservableCollection<Item> items = [];

    [ObservableProperty]
    private Item? selectedItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={SelectedItem.Id}");

        // Clear selection so the user can re-select the same item later
        SelectedItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _itemService.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Stops the spinner
        }
    }
}
```

**Key binding wiring:**

| XAML Property | ViewModel Property | Notes |
|---|---|---|
| `ItemsSource` | `ObservableCollection<Item>` | Must be `ObservableCollection`, not `List` |
| `SelectedItem` (TwoWay) | `Item? SelectedItem` | Set to `null` after navigating to allow re-selection |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap; triggers navigation |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-down gesture |
| `RefreshView.IsRefreshing` | `bool IsRefreshing` | Set `false` when done to hide spinner |

**Important details:**

- Always use `x:DataType` on `DataTemplate` for compiled bindings.
- Never use `ViewCell` — use `Grid`, `StackLayout`, or any `View` as the template root.
- Always update collections on the **UI thread** (`MainThread.BeginInvokeOnMainThread`).
- Clear `SelectedItem` after navigation so the same item can be tapped again.
